// Double chiffrement AES-256-GCM
const crypto = require('crypto');

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16;

function hexToBuffer(hex) {
  return Buffer.from(hex, 'hex');
}

function encryptLayer(data, keyHex) {
  const key = hexToBuffer(keyHex);
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
  const encrypted = Buffer.concat([cipher.update(data), cipher.final()]);
  const authTag = cipher.getAuthTag();
  return { iv, authTag, ciphertext: encrypted };
}

function doubleEncrypt(plaintext, keyA, keyB) {
  const data = Buffer.from(plaintext, 'utf-8');
  const layer1 = encryptLayer(data, keyA);
  const layer2 = encryptLayer(layer1.ciphertext, keyB);
  return Buffer.concat([
    layer1.iv, layer1.authTag,
    layer2.iv, layer2.authTag,
    layer2.ciphertext
  ]).toString('base64');
}

function encryptField(value, keyA, keyB) {
  if (value === null || value === undefined) return null;
  const str = typeof value === 'string' ? value : JSON.stringify(value);
  return doubleEncrypt(str, keyA, keyB);
}

